import React, { useState } from 'react';
import { Layout, Menu, Input, Avatar, Dropdown, Button, Breadcrumb } from 'antd';
import {
    MenuUnfoldOutlined, MenuFoldOutlined, SearchOutlined, BellOutlined, InfoCircleOutlined,
    UserOutlined, DashboardOutlined, SettingOutlined, SafetyCertificateOutlined,
    DatabaseOutlined, CustomerServiceOutlined, ShoppingOutlined
} from '@ant-design/icons';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';

import { MENU_PERMISSIONS } from '../../constants/roles';

const { Header, Sider, Content } = Layout;

// Giả lập hàm lấy user (bọc try catch chống crash)
const getCurrentUser = () => {
    try {
        const user = JSON.parse(localStorage.getItem('user'));
        return user || { "name": "Admin", "role": "Admin" };
    } catch (error) {
        return { "name": "Admin", "role": "staff" };
    }
};

const AdminLayout = () => {
    const [collapsed, setCollapsed] = useState(false);
    const navigate = useNavigate();
    const location = useLocation();

    const currentUser = getCurrentUser();

    // --- HÀM LỌC MENU THEO QUYỀN ---
    const checkPermission = (key) => {
        const allowedRoles = MENU_PERMISSIONS[key];
        if (!allowedRoles) return true;
        return allowedRoles.includes(currentUser.role);
    };

    // Hàm đệ quy lọc menu con 
    const filterMenuItems = (items) => {
        return items
            .filter(item => checkPermission(item.key))
            .map(item => {
                if (item.children) {
                    return { ...item, children: filterMenuItems(item.children) };
                }
                return item;
            });
    };

    // --- CẤU TRÚC MENU ---
    const allMainMenuItems = [
        {
            key: '/admin/dashboard',
            icon: <DashboardOutlined />,
            label: 'Dashboard'
        },
        // KINH DOANH
        {
            key: 'grp-sales',
            icon: <ShoppingOutlined />,
            label: 'Kinh Doanh',
            children: [
                { key: '/admin/orders', label: 'Đơn hàng' },
                { key: '/admin/customers', label: 'Khách hàng' },
                { key: '/admin/vouchers', label: 'Mã giảm giá' },
            ]
        },
        // HÀNG HÓA & KHO
        {
            key: 'grp-inventory',
            icon: <DatabaseOutlined />,
            label: 'Hàng Hóa & Kho',
            children: [
                { key: '/admin/products', label: 'Sản phẩm' },
                { key: '/admin/categories', label: 'Danh mục' },
                { key: '/admin/inventory', label: 'Nhập kho' },
                { key: '/admin/shipping', label: 'Vận chuyển' },
            ]
        },
        // CSKH & MARKETING
        {
            key: 'grp-marketing',
            icon: <CustomerServiceOutlined />,
            label: 'CSKH & Marketing',
            children: [
                { key: '/admin/chat', label: 'Tin nhắn (Chat)' },
                { key: '/admin/reviews', label: 'Đánh giá' },
                { key: '/admin/minigames', label: 'Minigame' },
                { key: '/admin/cms/banners', label: 'Banner & Blog' },
            ]
        },
        // QUẢN TRỊ HỆ THỐNG
        {
            key: 'grp-system',
            icon: <SafetyCertificateOutlined />,
            label: 'Hệ Thống',
            children: [
                { key: '/admin/staff', label: 'Nhân viên' },
                { key: '/admin/activity-logs', label: 'Nhật ký hoạt động' },
            ]
        },
    ];

    const allBottomMenuItems = [
        { key: '/admin/settings', icon: <SettingOutlined />, label: 'Cài đặt tài khoản' },
    ];

    // --- LỌC MENU ---
    const visibleMainMenu = filterMenuItems(allMainMenuItems);
    const visibleBottomMenu = filterMenuItems(allBottomMenuItems);

    // Logic Active Menu & Breadcrumb
    const currentPath = location.pathname;

    const findLabel = (items, path) => {
        for (const item of items) {
            if (item.key === path) return item.label;
            if (item.children) {
                const childLabel = findLabel(item.children, path);
                if (childLabel) return childLabel;
            }
        }
        return null;
    };

    const currentBreadcrumb = findLabel([...allMainMenuItems, ...allBottomMenuItems], currentPath) || 'Trang chủ';
    const activeKey = currentPath;

    const getOpenKeys = () => {
        for (const item of allMainMenuItems) {
            if (item.children && item.children.find(c => c.key === activeKey)) {
                return [item.key];
            }
        }
        return [];
    };

    // --- XỬ LÝ DROPDOWN USER (Fix cho Antd v5) ---
    const userMenu = {
        items: [
            { 
                key: '1', 
                label: 'Cài đặt', 
                onClick: () => navigate('/admin/settings') 
            },
            { 
                key: '2', 
                label: 'Đăng xuất', 
                danger: true, 
                onClick: () => {
                    localStorage.removeItem('user'); // Clear user khi đăng xuất
                    navigate('/admin/login');
                } 
            }
        ]
    };

    return (
        <Layout className="min-h-screen bg-[#F4F7FE]">
            {/* SIDEBAR */}
            <Sider
                trigger={null}
                collapsible
                collapsed={collapsed}
                width={260}
                collapsedWidth={80}
                theme="light" // Thêm theme light để chuẩn màu Antd
                className="border-r border-gray-100 shadow-sm"
                style={{
                    position: 'fixed', 
                    height: '100vh', 
                    left: 0, 
                    top: 0, 
                    bottom: 0, 
                    zIndex: 100,
                }}
            >
                <div className="flex flex-col h-full bg-white">
                    {/* Logo */}
                    <div className="h-24 flex items-center justify-center flex-shrink-0">
                        <h1 className={`font-bold text-blue-600 transition-all duration-300 ${collapsed ? 'text-sm' : 'text-2xl'}`}>
                            {collapsed ? 'FLW' : 'FLOWER SHOP'}
                        </h1>
                    </div>

                    {/* Menu Chính */}
                    <div className="flex-1 overflow-y-auto custom-scrollbar">
                        <Menu
                            mode="inline"
                            theme="light"
                            defaultOpenKeys={getOpenKeys()}
                            selectedKeys={[activeKey]}
                            items={visibleMainMenu}
                            onClick={({ key }) => navigate(key)}
                            className="border-none px-2 font-medium text-gray-600"
                        />
                    </div>

                    {/* Menu Đáy */}
                    <div className="flex-shrink-0 pb-4 bg-white">
                        <div className="mx-4 my-2 border-t border-gray-200"></div>
                        <Menu
                            mode="inline"
                            theme="light"
                            selectedKeys={[activeKey]}
                            items={visibleBottomMenu}
                            onClick={({ key }) => navigate(key)}
                            className="border-none px-2 font-medium text-gray-600"
                        />
                    </div>
                </div>
            </Sider>

            {/* CONTENT AREA */}
            <Layout
                className="bg-[#F4F7FE] transition-all duration-200 ease-in-out"
                style={{ marginLeft: collapsed ? 80 : 260 }}
            >
                {/* HEADER */}
                <Header 
                    style={{
                        padding: 0,             // Ghi đè padding mặc định của AntD
                        height: 'auto',         // Ghi đè height 64px của AntD
                        lineHeight: 'normal',   // Ghi đè line-height 64px của AntD
                        background: 'transparent'
                    }}
                    className="px-4 md:px-6 py-4 flex flex-col md:flex-row justify-between items-start md:items-center sticky top-0 z-50 backdrop-blur-xl bg-[#F4F7FE]/80"
                >
                    {/* Phần Trái: Breadcrumb & Title */}
                    <div className="flex flex-col mb-4 md:mb-0 w-full md:w-auto">
                        <Breadcrumb className="text-sm text-gray-500 mb-1">
                            <Breadcrumb.Item>Pages</Breadcrumb.Item>
                            <Breadcrumb.Item className="text-gray-800 font-medium">{currentBreadcrumb}</Breadcrumb.Item>
                        </Breadcrumb>
                        
                        <div className="flex items-center gap-2">
                            {/* Nút thu/phóng Menu cho Mobile (chỉ hiện trên màn hình nhỏ) */}
                            <Button 
                                type="text" 
                                icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />} 
                                onClick={() => setCollapsed(!collapsed)} 
                                className="flex md:hidden text-lg p-0 w-8 h-8 flex-shrink-0 text-gray-600" 
                            />
                            <h2 className="text-2xl md:text-3xl font-bold text-[#2B3674] m-0 tracking-tight">
                                {currentBreadcrumb}
                            </h2>
                        </div>
                    </div>

                    {/* Phần Phải: Search & Actions */}
                    <div className="flex items-center justify-between md:justify-end gap-2 md:gap-4 p-2 bg-white rounded-full shadow-sm w-full md:w-auto">

                        {/* Ô Tìm kiếm */}
                        <div className="flex items-center bg-[#F4F7FE] rounded-full px-4 py-1.5 flex-1 md:flex-none md:w-[220px]">
                            <SearchOutlined className="text-gray-400 mr-2" />
                            <Input 
                                placeholder="Tìm kiếm..." 
                                bordered={false} 
                                className="p-0 text-sm bg-transparent shadow-none focus:ring-0 w-full" 
                            />
                        </div>
                        
                        {/* Các icon thông báo & Avatar */}
                        <div className="flex items-center gap-3 pr-2 flex-shrink-0">
                            <BellOutlined className="text-xl text-gray-400 hover:text-blue-600 cursor-pointer transition-colors" />
                            <InfoCircleOutlined className="text-xl text-gray-400 hover:text-blue-600 cursor-pointer transition-colors" />
                            <Dropdown menu={userMenu} placement="bottomRight" trigger={['click']}>
                                <Avatar 
                                    className="bg-blue-600 cursor-pointer transform hover:scale-105 transition-transform shadow-md flex-shrink-0" 
                                    icon={<UserOutlined />} 
                                />
                            </Dropdown>
                        </div>
                    </div>
                </Header>

                {/* MAIN CONTENT ROUTER */}
                <Content className="m-4 md:m-6 mt-2">
                    <div className="bg-transparent min-h-[70vh] rounded-xl">
                        <Outlet />
                    </div>
                </Content>
            </Layout>
        </Layout>
    );
};

export default AdminLayout;

import React, { useState, useEffect } from 'react';
import { Table, Button, Input, Tag, message, Popconfirm, Avatar } from 'antd';
import { PlusOutlined, SearchOutlined, EditOutlined, DeleteOutlined, FileImageOutlined } from '@ant-design/icons';
import categoryService from '../../../services/categoryService'; // Import API Service
import CreateCategoryModal from './components/CreateCategoryModal';

const CategoryPage = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState([]);
  const [filteredData, setFilteredData] = useState([]);
  const [searchText, setSearchText] = useState('');
  const [editingItem, setEditingItem] = useState(null);

  // 1. Hàm gọi API lấy danh sách
  const fetchData = async () => {
    setLoading(true);
    try {
      const res = await categoryService.getAll();
      if (res.success) {
        // Gán key cho Table của Antd (dùng _id của MongoDB)
        const mappedData = res.data.map(item => ({ ...item, key: item._id }));
        setData(mappedData);
        setFilteredData(mappedData);
      }
    } catch (error) {
      message.error("Không thể tải danh sách danh mục");
    } finally {
      setLoading(false);
    }
  };

  // Gọi API khi component vừa chạy
  useEffect(() => {
    fetchData();
  }, []);

  // Xử lý tìm kiếm
  useEffect(() => {
    if (searchText.trim() === '') {
      setFilteredData(data);
    } else {
      const filtered = data.filter(item =>
        item.name.toLowerCase().includes(searchText.toLowerCase()) ||
        (item.description && item.description.toLowerCase().includes(searchText.toLowerCase()))
      );
      setFilteredData(filtered);
    }
  }, [searchText, data]);

  // 2. Xử lý Thêm mới hoặc Cập nhật
  const handleCreateOrUpdate = async (formData) => {
    try {
      if (editingItem) {
        // Nếu đang sửa -> Gọi API Update
        await categoryService.updateCategory(editingItem._id, formData);
        message.success('Cập nhật thành công!');
      } else {
        // Nếu tạo mới -> Gọi API Create
        await categoryService.createCategory(formData);
        message.success('Tạo danh mục mới thành công!');
      }

      setIsModalOpen(false);
      fetchData(); // Load lại bảng dữ liệu
    } catch (error) {
      message.error(error.response?.data?.message || 'Có lỗi xảy ra');
    }
  };

  // 3. Xử lý Xóa
  const handleDelete = async (id) => {
    try {
      await categoryService.deleteCategory(id);
      message.success('Đã xóa danh mục');
      fetchData(); // Load lại bảng
    } catch (error) {
      message.error('Xóa thất bại');
    }
  };

  // 4. Mở modal ở chế độ Sửa
  const openEditModal = (record) => {
    setEditingItem(record);
    setIsModalOpen(true);
  };

  // 5. Mở modal ở chế độ Thêm mới
  const openCreateModal = () => {
    setEditingItem(null);
    setIsModalOpen(true);
  };

  const columns = [
    {
      title: 'HÌNH ẢNH',
      dataIndex: 'image',
      key: 'image',
      width: 100,
      render: (img) => (
        <Avatar
          shape="square"
          size={64}
          src={img}
          icon={<FileImageOutlined />}
          className="rounded-lg border border-gray-200 bg-gray-50"
        />
      ),
    },
    {
      title: 'TÊN DANH MỤC',
      dataIndex: 'name',
      key: 'name',
      render: (text) => <span className="font-bold text-navy-700">{text}</span>,
    },
    {
      title: 'MÔ TẢ',
      dataIndex: 'description',
      key: 'description',
      className: 'text-gray-500',
    },
    {
      title: 'TRẠNG THÁI',
      dataIndex: 'isActive',
      key: 'isActive',
      width: 120,
      render: (isActive) => (
        <Tag color={isActive ? 'green' : 'red'} className="rounded-full px-3">
          {isActive ? 'Active' : 'Hidden'}
        </Tag>
      ),
    },
    {
      title: 'THAO TÁC',
      key: 'action',
      width: 120,
      render: (_, record) => (
        <div className="flex gap-2">
          <Button
            icon={<EditOutlined />}
            size="small"
            className="text-blue-500 border-blue-100 hover:bg-blue-50"
            onClick={() => openEditModal(record)}
          />
          <Popconfirm
            title="Xóa danh mục?"
            description="Hành động này không thể hoàn tác"
            onConfirm={() => handleDelete(record._id)}
            okText="Xóa"
            cancelText="Hủy"
            okButtonProps={{ danger: true }}
          >
            <Button
              icon={<DeleteOutlined />}
              size="small"
              danger
              className="border-red-100 hover:bg-red-50"
            />
          </Popconfirm>
        </div>
      ),
    },
  ];

  return (
    <div className="w-full">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <div>
        </div>
        <Button
          type="primary"
          icon={<PlusOutlined />}
          onClick={openCreateModal}
          className="bg-brand-500 h-10 px-6 rounded-xl font-bold shadow-lg shadow-brand-500/50 border-none hover:bg-brand-600"
        >
          Thêm Mới
        </Button>
      </div>

      {/* Main Table */}
      <div className="bg-white p-6 rounded-[20px] shadow-sm">
        <div className="flex justify-between mb-6">
          <Input
            prefix={<SearchOutlined className="text-gray-400" />}
            placeholder="Tìm kiếm theo tên hoặc mô tả..."
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            allowClear
            className="w-[400px] h-[40px] rounded-xl bg-[#F4F7FE] border-none hover:bg-gray-100 focus:bg-white transition-all"
          />
          <div className="text-gray-500">
            Tổng: <span className="font-semibold text-navy-700">{filteredData.length}</span> danh mục
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={filteredData}
          loading={loading}
          pagination={{
            pageSize: 8,
            showTotal: (total, range) => `${range[0]}-${range[1]} của ${total} danh mục`,
          }}
          className="custom-table-metrix"
        />
      </div>

      <CreateCategoryModal
        open={isModalOpen}
        onCancel={() => setIsModalOpen(false)}
        onSuccess={handleCreateOrUpdate}
        initialData={editingItem}
      />
    </div>
  );
};

export default CategoryPage;

import React, { useState } from 'react';
import { Table, Button, Input, Select, Tag, Avatar, Drawer, Tabs, List, Card, Row, Col, Statistic, Dropdown, Menu, message } from 'antd';
import {
    PlusOutlined, SearchOutlined, UserOutlined,
    ShoppingOutlined, DollarOutlined, EnvironmentOutlined,
    HistoryOutlined, MoreOutlined, EditOutlined, StopOutlined,
    SafetyCertificateOutlined, MailOutlined, PhoneOutlined
} from '@ant-design/icons';
import CreateCustomerModal from './components/CreateCustomerModal';

const { Option } = Select;

// --- DỮ LIỆU GIẢ LẬP NÂNG CAO ---
const MOCK_CUSTOMERS = [
    {
        key: '1', id: 'CUS-001', name: 'Nguyễn Văn An', email: 'an.nguyen@gmail.com', phone: '0909123456',
        avatar: 'https://i.pravatar.cc/150?img=11',
        rank: 'Gold', points: 1540, totalSpent: 15500000, orderCount: 12, status: 'Active',
        address: '123 Lê Lợi, Q.1, TP.HCM',
        joinDate: '20/01/2025'
    },
    {
        key: '2', id: 'CUS-002', name: 'Trần Thị Bích', email: 'bich.tran@yahoo.com', phone: '0912345678',
        avatar: 'https://i.pravatar.cc/150?img=5',
        rank: 'Silver', points: 450, totalSpent: 4200000, orderCount: 5, status: 'Active',
        address: '45 Nguyễn Huệ, Q.1, TP.HCM',
        joinDate: '15/05/2025'
    },
    {
        key: '3', id: 'CUS-003', name: 'Lê Hoàng Cường', email: 'cuong.le@outlook.com', phone: '0987654321',
        avatar: 'https://i.pravatar.cc/150?img=3',
        rank: 'Bronze', points: 50, totalSpent: 550000, orderCount: 1, status: 'Blocked',
        address: '12 Xô Viết Nghệ Tĩnh, Bình Thạnh',
        joinDate: '10/12/2025'
    },
];

const MOCK_HISTORY = [
    { id: '#ORD-992', date: '30/01/2026', total: '1,200,000đ', status: 'Completed' },
    { id: '#ORD-980', date: '15/01/2026', total: '850,000đ', status: 'Completed' },
    { id: '#ORD-901', date: '01/01/2026', total: '2,500,000đ', status: 'Cancelled' },
];

const CustomersPage = () => {
    const [data, setData] = useState(MOCK_CUSTOMERS);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [drawerVisible, setDrawerVisible] = useState(false);
    const [selectedCustomer, setSelectedCustomer] = useState(null);

    // Mở chi tiết khách hàng
    const showDetail = (record) => {
        setSelectedCustomer(record);
        setDrawerVisible(true);
    };

    const handleCreate = (newItem) => {
        setData([newItem, ...data]);
        setIsModalOpen(false);
    };

    const renderRank = (rank) => {
        let color = rank === 'Gold' ? 'gold' : (rank === 'Silver' ? 'cyan' : 'orange');
        return <Tag icon={<SafetyCertificateOutlined />} color={color}>{rank} Member</Tag>;
    };

    const columns = [
        {
            title: 'KHÁCH HÀNG',
            dataIndex: 'name',
            render: (text, record) => (
                <div className="flex items-center gap-3 cursor-pointer" onClick={() => showDetail(record)}>
                    <Avatar src={record.avatar} size={40} />
                    <div>
                        <h5 className="font-bold text-navy-700 text-sm m-0 hover:text-brand-500">{text}</h5>
                        <span className="text-gray-400 text-xs">{record.email}</span>
                    </div>
                </div>
            ),
        },
        {
            title: 'HẠNG THÀNH VIÊN',
            dataIndex: 'rank',
            render: (rank) => renderRank(rank),
        },
        {
            title: 'CHI TIÊU',
            dataIndex: 'totalSpent',
            render: (val) => <span className="font-bold text-navy-700">{val.toLocaleString()} đ</span>,
            sorter: (a, b) => a.totalSpent - b.totalSpent,
        },
        {
            title: 'ĐƠN HÀNG',
            dataIndex: 'orderCount',
            render: (val) => <div className="text-center w-10 bg-gray-100 rounded-md font-bold text-sm">{val}</div>,
        },
        {
            title: 'TRẠNG THÁI',
            dataIndex: 'status',
            render: (status) => (
                <Tag color={status === 'Active' ? 'green' : 'red'}>{status === 'Active' ? 'Hoạt động' : 'Đã khóa'}</Tag>
            ),
        },
        {
            title: '',
            key: 'action',
            render: (_, record) => (
                <Dropdown overlay={<Menu items={[
                    { key: '1', label: 'Xem chi tiết', icon: <UserOutlined />, onClick: () => showDetail(record) },
                    { key: '2', label: 'Sửa thông tin', icon: <EditOutlined /> },
                    { key: '3', label: 'Khóa tài khoản', icon: <StopOutlined />, danger: true },
                ]} />}>
                    <Button type="text" icon={<MoreOutlined />} />
                </Dropdown>
            ),
        },
    ];

    // --- NỘI DUNG DRAWER CHI TIẾT ---
    const renderCustomerDetailContent = () => (
        <div>
            {/* Header Profile */}
            <div className="flex items-center gap-4 mb-6 p-4 bg-gradient-to-r from-blue-50 to-white rounded-2xl">
                <Avatar src={selectedCustomer?.avatar} size={80} className="border-4 border-white shadow-sm" />
                <div>
                    <h2 className="text-2xl font-bold text-navy-700 m-0">{selectedCustomer?.name}</h2>
                    <div className="flex gap-2 mt-2">
                        {renderRank(selectedCustomer?.rank)}
                        <Tag>Tham gia: {selectedCustomer?.joinDate}</Tag>
                    </div>
                </div>
            </div>

            {/* Quick Stats */}
            <Row gutter={16} className="mb-6">
                <Col span={8}>
                    <Card size="small" className="rounded-xl bg-gray-50 border-none">
                        <Statistic title="Tổng chi tiêu" value={selectedCustomer?.totalSpent} suffix="đ" valueStyle={{ color: '#4318FF', fontWeight: 'bold' }} />
                    </Card>
                </Col>
                <Col span={8}>
                    <Card size="small" className="rounded-xl bg-gray-50 border-none">
                        <Statistic title="Số đơn hàng" value={selectedCustomer?.orderCount} prefix={<ShoppingOutlined />} />
                    </Card>
                </Col>
                <Col span={8}>
                    <Card size="small" className="rounded-xl bg-gray-50 border-none">
                        <Statistic title="Điểm thưởng" value={selectedCustomer?.points} prefix={<DollarOutlined />} valueStyle={{ color: '#FAAD14' }} />
                    </Card>
                </Col>
            </Row>

            {/* Detail Tabs */}
            <Tabs defaultActiveKey="1" items={[
                {
                    key: '1', label: 'Thông tin liên hệ',
                    children: (
                        <div className="flex flex-col gap-4 mt-2">
                            <div className="flex items-center gap-3 p-3 bg-white border border-gray-100 rounded-xl">
                                <div className="w-10 h-10 rounded-full bg-blue-50 text-blue-500 flex items-center justify-center text-xl"><MailOutlined /></div>
