import React, { useState } from 'react';
import { Modal, Form, Input, Select, DatePicker, InputNumber, Switch, Button, message, Row, Col, Divider } from 'antd';
import { ReloadOutlined, PercentageOutlined, DollarOutlined } from '@ant-design/icons';
import dayjs from 'dayjs';

const { Option } = Select;
const { RangePicker } = DatePicker;
const { TextArea } = Input;

const CreateVoucherModal = ({ open, onCancel, onCreate }) => {
  const [form] = Form.useForm();
  const [discountType, setDiscountType] = useState('percent'); // 'percent' hoặc 'fixed'

  // Hàm tạo mã ngẫu nhiên
  const generateCode = () => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let code = '';
    for (let i = 0; i < 8; i++) {
      code += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    form.setFieldsValue({ code: `FLW-${code}` });
  };

  const handleOk = async () => {
    try {
      const values = await form.validateFields();
      
      const newVoucher = {
        key: Date.now(),
        id: Math.floor(Math.random() * 1000),
        ...values,
        startDate: values.time ? values.time[0].format('DD/MM/YYYY') : '',
        endDate: values.time ? values.time[1].format('DD/MM/YYYY') : '',
        used: 0,
        status: values.isActive ? 'Active' : 'Hidden'
      };

      onCreate(newVoucher);
      form.resetFields();
      message.success('Tạo mã giảm giá thành công!');
    } catch (error) {
      console.log('Validate Failed:', error);
    }
  };

  return (
    <Modal
      title={<span className="text-xl font-bold text-navy-700">Tạo Mã Giảm Giá Mới</span>}
      open={open}
      onOk={handleOk}
      onCancel={onCancel}
      width={700}
      okText="Lưu Mã"
      cancelText="Hủy"
      centered
      className="custom-modal-metrix"
    >
      <Form 
        form={form} 
        layout="vertical" 
        className="mt-5"
        initialValues={{ 
          type: 'percent', 
          isActive: true, 
          limit: 100 
        }}
      >
        {/* --- MÃ CODE & TÊN --- */}
        <Row gutter={16}>
          <Col span={12}>
             <Form.Item label="Mã Voucher (Code)" name="code" rules={[{ required: true, message: 'Cần có mã code' }]}>
               <Input 
                 placeholder="VD: TET2026" 
                 className="rounded-xl h-[40px] font-bold uppercase text-brand-500" 
                 addonAfter={<ReloadOutlined onClick={generateCode} className="cursor-pointer hover:text-brand-500" />}
               />
             </Form.Item>
          </Col>
          <Col span={12}>
             <Form.Item label="Tên chương trình" name="name" rules={[{ required: true }]}>
               <Input placeholder="VD: Khuyến mãi Tết" className="rounded-xl h-[40px]" />
             </Form.Item>
          </Col>
        </Row>

        {/* --- CẤU HÌNH GIẢM GIÁ --- */}
        <div className="bg-gray-50 p-4 rounded-xl mb-4">
           <Row gutter={16}>
             <Col span={8}>
               <Form.Item label="Loại giảm giá" name="type">
                 <Select 
                    className="rounded-xl h-[40px] custom-select-metrix" 
                    onChange={setDiscountType}
                 >
                   <Option value="percent"><PercentageOutlined /> Theo phần trăm</Option>
                   <Option value="fixed"><DollarOutlined /> Số tiền cố định</Option>
                 </Select>
               </Form.Item>
             </Col>
             <Col span={8}>
               <Form.Item 
                  label="Giá trị giảm" 
                  name="value" 
                  rules={[{ required: true }]}
                >
                 <InputNumber 
                    className="w-full rounded-xl h-[40px] flex items-center pt-1 font-bold"
                    formatter={value => discountType === 'percent' ? `${value}%` : `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
                    parser={value => value.replace(/%|\s?|(,*)/g, '')}
                 />
               </Form.Item>
             </Col>
             
             {/* Chỉ hiện 'Giảm tối đa' nếu chọn theo % */}
             {discountType === 'percent' && (
               <Col span={8}>
                 <Form.Item label="Giảm tối đa (VNĐ)" name="maxDiscount">
                   <InputNumber 
                      className="w-full rounded-xl h-[40px] flex items-center pt-1" 
                      formatter={value => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
                      placeholder="Không giới hạn"
                   />
                 </Form.Item>
               </Col>
             )}
           </Row>

           <Row gutter={16}>
             <Col span={12}>
               <Form.Item label="Đơn hàng tối thiểu (VNĐ)" name="minOrder">
                 <InputNumber 
                    className="w-full rounded-xl h-[40px] flex items-center pt-1" 
                    formatter={value => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
                    placeholder="0"
                 />
               </Form.Item>
             </Col>
             <Col span={12}>
               <Form.Item label="Tổng lượt dùng tối đa" name="limit">
                 <InputNumber className="w-full rounded-xl h-[40px] flex items-center pt-1" placeholder="Vô hạn" />
               </Form.Item>
             </Col>
           </Row>
        </div>

        {/* --- THỜI GIAN & TRẠNG THÁI --- */}
        <Row gutter={16}>
          <Col span={16}>
            <Form.Item label="Thời gian áp dụng" name="time" rules={[{ required: true }]}>
               <RangePicker showTime className="w-full rounded-xl h-[40px] bg-[#F4F7FE] border-none" />
            </Form.Item>
          </Col>
          <Col span={8}>
             <Form.Item label="Kích hoạt ngay" name="isActive" valuePropName="checked">
               <Switch checkedChildren="Bật" unCheckedChildren="Tắt" defaultChecked />
             </Form.Item>
          </Col>
        </Row>

        <Form.Item name="description" label="Mô tả / Ghi chú">
          <TextArea rows={2} placeholder="Điều kiện áp dụng..." className="rounded-xl" />
        </Form.Item>
      </Form>
    </Modal>
  );
};

export default CreateVoucherModal;

import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Trash2, ArrowRight, ShoppingBag, Loader2 } from "lucide-react";
import cartService from "../../../services/cartService";
import { message } from "antd";

const Cart = () => {
  const navigate = useNavigate();
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchCart = async () => {
    try {
      const res = await cartService.getCart();
      if (res.success) {
        setCart(res.data);
      }
    } catch (error) {
      console.error("Lỗi lấy giỏ hàng:", error);
      // Nếu lỗi 401 Unauthorized (chưa đăng nhập), chuyển hướng
      if (error?.response?.status === 401) {
        message.warning("Vui lòng đăng nhập để xem giỏ hàng");
        navigate("/login");
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCart();
  }, []);

  const handleUpdateQuantity = async (itemId, currentQuantity, change) => {
    const newQuantity = currentQuantity + change;
    if (newQuantity < 1) return;

    // TODO: Nên có debounce ở đây để tránh call API liên tục (sẽ làm ở file riêng nếu phức tạp)
    try {
      await cartService.updateQuantity(itemId, newQuantity);
      fetchCart(); // Gọi lại để lấy giá mới và stock validation từ BE
    } catch (error) {
      message.error(error?.response?.data?.message || "Lỗi cập nhật số lượng");
    }
  };

  const handleRemoveItem = async (itemId) => {
    try {
      await cartService.removeItem(itemId);
      message.success("Đã xóa khỏi giỏ hàng");
      fetchCart();
    } catch (error) {
      message.error("Lỗi khi xóa sản phẩm");
    }
  };

  if (loading) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center text-pink-400">
        <Loader2 className="animate-spin w-12 h-12 mb-4" />
        <p>Đang tải giỏ hàng...</p>
      </div>
    );
  }

  // Tách items thường và items AI custom
  const regularItems = cart?.items || [];
  const customItems = cart?.customBouquets || [];
  const hasItems = regularItems.length > 0 || customItems.length > 0;

  return (
    <div className="bg-[#fffafc] min-h-screen py-16 px-6">
      <div className="max-w-7xl mx-auto">

        <div className="flex items-center gap-3 mb-10">
          <ShoppingBag className="text-pink-500 w-8 h-8" />
          <h1 className="text-3xl font-bold text-gray-800">Giỏ Hàng Của Bạn</h1>
        </div>

        {!hasItems ? (
          <div className="bg-white rounded-3xl p-16 text-center shadow-sm border border-pink-100 flex flex-col items-center">
            <img src="https://res.cloudinary.com/drwles2k0/image/upload/v1772271283/flower_lmks7o.png" className="w-24 mb-6 opacity-50" alt="Empty" />
            <h2 className="text-xl font-medium text-gray-600 mb-2">Giỏ hàng đang trống</h2>
            <p className="text-gray-400 mb-8">Bạn chưa mổ bó hoa nào cả, hãy dạo quanh shop nhé!</p>
            <Link
              to="/shop"
              className="bg-pink-400 text-white px-8 py-3 rounded-full hover:bg-pink-500 font-medium transition shadow-md hover:shadow-lg flex items-center gap-2"
            >
              Tiếp tục mua hàng <ArrowRight size={18} />
            </Link>
          </div>
        ) : (
          <div className="grid lg:grid-cols-3 gap-10">
            {/* DANH SÁCH SẢN PHẨM */}
            <div className="lg:col-span-2 space-y-6">

              {/* Hoa Thường */}
              {regularItems.length > 0 && (
                <div className="bg-white rounded-3xl p-6 shadow-sm border border-emerald-50">
                  <h3 className="font-semibold text-emerald-500 mb-4 border-b pb-2">Hoa theo mẫu</h3>
                  <div className="space-y-6">
                    {regularItems.map((item) => (
                      <div key={item._id} className="flex gap-4 items-center bg-gray-50/50 p-4 rounded-2xl">
                        <img
                          src={item.product?.images?.[0]?.url || "https://placehold.co/100"}
                          alt={item.product?.name}
                          className="w-24 h-24 object-cover rounded-xl border border-gray-100"
                        />
                        <div className="flex-1">
                          <Link to={`/product/${item.product?._id}`} className="font-medium text-gray-800 hover:text-pink-500 transition line-clamp-1">
                            {item.product?.name || "Sản phẩm đã bị xóa"}
                          </Link>
                          <p className="text-pink-500 font-bold mt-1">
                            {item.price.toLocaleString()} đ
                          </p>
                        </div>

                        {/* Quantity */}
                        <div className="flex items-center gap-3 bg-white border border-pink-100 rounded-full px-2 py-1 shadow-sm">
                          <button
                            onClick={() => handleUpdateQuantity(item._id, item.quantity, -1)}
                            className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-pink-50 text-pink-500 font-medium"
                          >
                            -
                          </button>
                          <span className="w-6 text-center text-sm font-medium">{item.quantity}</span>
                          <button
                            onClick={() => handleUpdateQuantity(item._id, item.quantity, 1)}
                            className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-pink-50 text-pink-500 font-medium"
                          >
                            +
                          </button>
                        </div>

                        {/* Tổng tiền của item */}
                        <div className="w-28 text-right font-medium text-gray-700">
                          {(item.price * item.quantity).toLocaleString()} đ
                        </div>

                        {/* Nút xóa */}
                        <button
                          onClick={() => handleRemoveItem(item._id)}
                          className="w-10 h-10 flex items-center justify-center rounded-full text-red-400 hover:bg-red-50 transition"
                          title="Xóa"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Hoa Thiết Kế (AI) */}
              {customItems.length > 0 && (
                <div className="bg-white rounded-3xl p-6 shadow-sm border border-purple-50">
                  <h3 className="font-semibold text-purple-500 mb-4 border-b pb-2 flex justify-between items-center">
                    <span>Hoa thiết kế AI (Rosee)</span>
                    <span className="text-xs font-normal text-purple-400 bg-purple-50 px-2 py-1 rounded">Sản phẩm độc quyền</span>
                  </h3>
                  <div className="space-y-6">
                    {customItems.map((item, idx) => (
                      <div key={idx} className="flex gap-4 items-center bg-purple-50/30 p-4 rounded-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-2 h-full bg-purple-200"></div>
                        <img
                          src={item.imageUrl}
                          alt="AI Bouquet"
                          className="w-24 h-24 object-cover rounded-xl border border-purple-100"
                        />
                        <div className="flex-1">
                          <p className="font-medium text-purple-800">
                            Bó hoa thiết kế riêng #{idx + 1}
                          </p>
                          <p className="text-sm text-gray-500 mt-1 italic line-clamp-2">
                            "{item.messageContent}"
                          </p>
                          <p className="text-purple-600 font-bold mt-1">
                            {item.totalCustomPrice.toLocaleString()} đ
                          </p>
                        </div>

                        {/* Note: Hoa AI custom số lượng luôn mặc định là 1 (hoặc theo thiết kế hiện tại) */}
                        <div className="w-24 text-center font-medium text-gray-400 text-sm">
                          SL: 1
                        </div>

                        <div className="w-28 text-right font-medium text-gray-700">
                          {item.totalCustomPrice.toLocaleString()} đ
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

            </div>

            {/* TỔNG KẾT (TÍNH TIỀN) */}
            <div className="bg-white rounded-3xl shadow-lg border border-pink-100 p-8 h-fit sticky top-24">
              <h3 className="text-xl font-bold text-gray-800 mb-6">Tổng đơn hàng</h3>

              <div className="space-y-4 mb-6 text-sm text-gray-600">
                <div className="flex justify-between">
                  <span>Tạm tính ({regularItems.length + customItems.length} loại)</span>
                  <span className="font-medium">
                    {cart?.totalPrice?.toLocaleString()} đ
                  </span>
                </div>
                <div className="flex justify-between text-emerald-500">
                  <span>Khuyến mãi</span>
                  <span>0 đ</span>
                </div>
              </div>

              <div className="border-t border-dashed border-gray-200 pt-4 mb-8">
                <div className="flex justify-between items-end">
                  <span className="text-gray-800 font-medium">Tổng cộng</span>
                  <div className="text-right">
                    <span className="text-3xl font-bold text-pink-500 block">
                      {cart?.totalPrice?.toLocaleString()} đ
                    </span>
                    <span className="text-xs text-gray-400">(Chưa bao gồm phí vận chuyển)</span>
                  </div>
                </div>
              </div>

              <Link
                to="/checkout"
                className="w-full bg-gradient-to-r from-pink-400 to-pink-500 hover:from-pink-500 hover:to-pink-600 text-white py-4 rounded-2xl font-bold text-lg transition shadow-md hover:shadow-lg flex items-center justify-center gap-2"
              >
                Tiến hành thanh toán
              </Link>
            </div>

          </div>
        )}

      </div>
    </div>
  );
};

export default Cart;

import { useState, useEffect } from "react";
import { Star, Loader2, Heart } from "lucide-react";
import { useParams, useNavigate } from "react-router-dom";
import productService from "../../../services/productService";
import cartService from "../../../services/cartService";
import authService from "../../../services/authService";
import reviewService from "../../../services/reviewService";
import wishlistService from "../../../services/wishlistService";
import ProductCard from "../../components/common/user/ProductCard/ProductCard";
import { message, Rate } from "antd";

const ProductDetail = () => {
  const navigate = useNavigate();
  const { id } = useParams();

  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [mainImage, setMainImage] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState([]);

  // Wishlist and Reviews state
  const [liked, setLiked] = useState(false);
  const [reviews, setReviews] = useState([]);
  const [reviewParams, setReviewParams] = useState({ page: 1, limit: 5 });
  const [totalReviews, setTotalReviews] = useState(0);

  // New review form state
  const [newReviewRating, setNewReviewRating] = useState(5);
  const [newReviewComment, setNewReviewComment] = useState("");
  const [submittingReview, setSubmittingReview] = useState(false);

  useEffect(() => {
    const fetchProductDetails = async () => {
      setLoading(true);
      setError(null);
      try {
        const res = await productService.get(id);
        if (res.success) {
          setProduct(res.data);
          setMainImage(res.data.images?.[0]?.url || "");

          // Sync liked status from local storage
          const localWish = JSON.parse(localStorage.getItem("wishlist")) || [];
          if (localWish.some(item => (item._id || item.id) === id)) {
            setLiked(true);
          } else {
            setLiked(false);
          }

          // Fetch related products
          if (res.data.category?._id) {
            const relatedRes = await productService.getAll({
              category: res.data.category._id,
              limit: 5 // Get 5, will filter out self later to keep 4
            });
            if (relatedRes.success) {
              setRelatedProducts(relatedRes.data);
            }
          }
        }
      } catch (err) {
        console.error("Lỗi lấy chi tiết sản phẩm:", err);
        setError("Không tìm thấy sản phẩm 😢");
      } finally {
        setLoading(false);
        window.scrollTo({ top: 0, behavior: "smooth" });
      }
    };

    const fetchReviews = async () => {
      try {
        const res = await reviewService.getProductReviews(id, reviewParams);
        if (res.success) {
          setReviews(res.data || []);
          setTotalReviews(res.total || res.data?.length || 0);
        }
      } catch (err) {
        console.error("Lỗi báo cáo:", err);
      }
    };

    if (id) {
      fetchProductDetails();
      fetchReviews();
    }
  }, [id, reviewParams.page]);

  const [addingToCart, setAddingToCart] = useState(false);

  const handleAddToCart = async () => {
    if (!authService.isLoggedIn()) {
      message.warning("Vui lòng đăng nhập để mổ hàng");
      navigate("/login");
      return;
    }

    setAddingToCart(true);
    try {
      const res = await cartService.addToCart(product._id, quantity);
      if (res.success) {
        message.success(`Đã thêm ${quantity} x ${product.name} vào giỏ`);
        // Dispatch event để Navbar tự động update số lượng nếu cần
        window.dispatchEvent(new Event("cartUpdated"));
      }
    } catch (error) {
      message.error(error?.response?.data?.message || "Lỗi khi thêm vào giỏ hàng");
    } finally {
      setAddingToCart(false);
    }
  };

  const [togglingWishlist, setTogglingWishlist] = useState(false);
  const handleToggleWishlist = async () => {
    if (!authService.isLoggedIn()) {
      message.warning({ content: "Vui lòng đăng nhập để lưu sản phẩm", key: "wishlist" });
      return;
    }
    if (togglingWishlist) return;

    setTogglingWishlist(true);
    let wishlist = JSON.parse(localStorage.getItem("wishlist")) || [];

    try {
      const res = await wishlistService.toggleWishlist(product._id);
      if (res.success) {
        if (liked) {
          wishlist = wishlist.filter((item) => (item._id || item.id) !== product._id);
          setLiked(false);
          message.success({ content: "Đã xoá khỏi danh sách yêu thích", key: "wishlist" });
        } else {
          wishlist.push(product);
          setLiked(true);
          message.success({ content: "Đã thêm vào danh sách yêu thích", key: "wishlist" });
        }
        localStorage.setItem("wishlist", JSON.stringify(wishlist));
        window.dispatchEvent(new Event("wishlistUpdated"));
      }
    } catch (error) {
      message.error({ content: "Lỗi khi cập nhật danh sách yêu thích", key: "wishlist" });
    } finally {
      setTogglingWishlist(false);
    }
  };

  const submitReview = async (e) => {
    e.preventDefault();
    if (!authService.isLoggedIn()) {
      message.warning("Vui lòng đăng nhập để đánh giá sản phẩm");
      return;
    }
    if (!newReviewComment.trim()) {
      message.warning("Vui lòng nhập nội dung đánh giá");
      return;
    }

    setSubmittingReview(true);
    try {
      const res = await reviewService.addReview(id, newReviewRating, newReviewComment);
      if (res.success) {
        message.success("Cảm ơn bạn đã đánh giá!");
        setNewReviewComment("");
        setNewReviewRating(5);
        // Refresh reviews
        const refreshRes = await reviewService.getProductReviews(id, reviewParams);
        if (refreshRes.success) {
          setReviews(refreshRes.data || []);
          setTotalReviews(refreshRes.total || refreshRes.data?.length || 0);
        }
      }
    } catch (error) {
      message.error(error?.response?.data?.message || "Lỗi khi gửi đánh giá");
    } finally {
      setSubmittingReview(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center p-10 text-pink-400">
        <Loader2 className="animate-spin w-12 h-12 mb-4" />
        <p>Đang tải hoa xinh...</p>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="min-h-screen flex items-center justify-center p-10 text-center text-gray-500 text-xl font-medium">
        {error || "Không tìm thấy sản phẩm 😢"}
      </div>
    );
  }

  // Filter out self, get exactly 4 related
  const filteredRelated = relatedProducts.filter(p => p._id !== product._id).slice(0, 4);

  return (
    <div className="bg-[#fffafc] min-h-screen py-16 px-6">
      <div className="max-w-7xl mx-auto grid md:grid-cols-2 gap-16">

        {/* IMAGE SECTION */}
        <div>
          <div className="rounded-3xl overflow-hidden shadow-lg mb-6 border border-pink-100">
            <img
              src={mainImage || "https://placehold.co/600x600?text=No+Image"}
              alt={product.name}
              className="w-full h-[500px] object-cover"
            />
          </div>

          <div className="flex gap-4 overflow-x-auto pb-2">
            {product.images?.map((img, index) => (
              <img
                key={index}
                src={img.url}
                alt=""
                onClick={() => setMainImage(img.url)}
                className={`w-24 h-24 object-cover rounded-xl cursor-pointer border-2 transition-all ${mainImage === img.url
                  ? "border-pink-500 scale-105"
                  : "border-transparent opacity-80 hover:opacity-100"
                  }`}
              />
            ))}
          </div>
        </div>

        {/* INFO SECTION */}
        <div>
          <h1 className="text-4xl font-bold text-gray-800 mb-4 leading-tight">
            {product.name}
          </h1>

          <div className="flex items-center gap-4 mb-6">
            <p className="text-pink-500 text-3xl font-bold">
              {product.price.toLocaleString()} đ
            </p>
            {product.originalPrice > product.price && (
              <p className="text-gray-400 text-xl font-medium line-through">
                {product.originalPrice.toLocaleString()} đ
              </p>
            )}
            {product.originalPrice > product.price && (
              <span className="bg-pink-100 text-pink-600 px-3 py-1 rounded-full text-sm font-bold">
                -{Math.round((product.originalPrice - product.price) / product.originalPrice * 100)}%
              </span>
            )}
          </div>

          <p className="text-gray-600 mb-6 text-lg leading-relaxed whitespace-pre-line">
            {product.description}
          </p>

          <p className="text-sm text-pink-500 mb-6 font-medium bg-pink-50 inline-block px-4 py-2 rounded-full">
            Danh mục: {product.category?.name || "Khác"}
          </p>

          <div className="flex items-center gap-4 mt-3 text-sm">
            <div className="flex items-center gap-1 bg-yellow-50 px-3 py-1.5 rounded-full border border-yellow-100">
              <span className="text-yellow-400">★</span>
              <span className="text-gray-700 font-medium">
                {product.averageRating || 5.0}
              </span>
            </div>

            <div className="flex items-center gap-1 bg-emerald-50 px-3 py-1.5 rounded-full border border-emerald-100">
              <span className="text-emerald-400">✔</span>
              <span className="text-gray-600">
                {product.sold || 0} đã bán
              </span>
            </div>

            <div className="flex items-center gap-1 bg-blue-50 px-3 py-1.5 rounded-full border border-blue-100">
              <span className="text-blue-500">Kho: {product.stock > 0 ? product.stock : "Hết hàng"}</span>
            </div>
          </div>

          <div className="mt-8">
            <h3 className="text-lg font-semibold text-emerald-500 mb-4">
              Chính sách của shop
            </h3>
            <div className="space-y-3">
              <div className="flex items-center gap-3 bg-white shadow-sm rounded-xl p-3 border border-gray-50">
                <div className="w-8 h-8 flex items-center justify-center rounded-full border-2 border-pink-200 text-pink-400 font-bold">✓</div>
                <p className="text-gray-600 text-sm">Cam kết hoa tươi 100%</p>
              </div>
              <div className="flex items-center gap-3 bg-white shadow-sm rounded-xl p-3 border border-gray-50">
                <div className="w-8 h-8 flex items-center justify-center rounded-full border-2 border-pink-200 text-pink-400 font-bold">✓</div>
                <p className="text-gray-600 text-sm">Hoàn tiền nếu sản phẩm lỗi</p>
              </div>
            </div>
          </div>

          {/* Quantity */}
          <div className="flex items-center gap-4 mt-8 mb-6">
            <span className="text-gray-600 font-medium">Số lượng:</span>
            <div className="flex items-center gap-3">
              <button
                onClick={() => setQuantity(q => Math.max(1, q - 1))}
                className="w-10 h-10 rounded-full border-2 border-pink-200 text-pink-500 hover:bg-pink-50 transition font-bold text-lg"
              >
                -
              </button>
              <span className="text-lg font-bold text-gray-800 w-8 text-center">
                {quantity}
              </span>
              <button
                onClick={() => setQuantity(q => Math.min(product.stock, q + 1))}
                className="w-10 h-10 rounded-full border-2 border-pink-200 text-pink-500 hover:bg-pink-50 transition font-bold text-lg"
              >
                +
              </button>
            </div>
          </div>

          {/* BUTTONS */}
          <div className="flex gap-4 mt-6">
            <button
              onClick={handleAddToCart}
              disabled={product.stock === 0 || addingToCart}
              className="flex-1 bg-pink-500 hover:bg-pink-600 disabled:opacity-50 text-white py-4 rounded-2xl font-bold text-lg transition shadow-md hover:shadow-lg flex items-center justify-center gap-2"
            >
              {addingToCart && <Loader2 size={20} className="animate-spin" />}
              {product.stock > 0 ? (addingToCart ? "Đang thêm..." : "Thêm vào giỏ") : "Hết hàng"}
            </button>
            <button
              onClick={handleToggleWishlist}
              disabled={togglingWishlist}
              className={`w-14 h-14 flex items-center justify-center rounded-2xl border-2 transition ${liked ? 'border-pink-500 bg-pink-50 text-pink-500' : 'border-pink-200 text-pink-400 hover:bg-pink-50 hover:text-pink-500'}`}
            >
              <Heart size={24} className={liked ? 'fill-pink-500' : ''} />
            </button>
          </div>

        </div>
      </div>

      {/* RATING SECTION */}
      <div className="max-w-7xl mx-auto mt-20">
        <h2 className="text-emerald-400 text-2xl font-bold mb-6">Đánh giá sản phẩm</h2>
        <div className="bg-white rounded-3xl shadow-sm border border-emerald-50 p-10">
          <div className="grid md:grid-cols-3 gap-10">
            {/* Left summary */}
            <div className="md:col-span-1 border-r border-gray-100 pr-8">
              <div className="text-center">
                <p className="text-6xl font-bold text-pink-500 mb-2">{product.averageRating?.toFixed(1) || "5.0"}</p>
                <div className="mb-2">
                  <Rate disabled defaultValue={product.averageRating || 5} className="text-yellow-400 text-2xl" />
                </div>
                <p className="text-gray-500">{totalReviews} đánh giá</p>
              </div>

              {/* Form đánh giá (nếu đã đăng nhập) */}
              <div className="mt-8 pt-8 border-t border-gray-100">
                <h3 className="font-semibold text-gray-700 mb-4 text-center">Gửi Đánh Giá Của Bạn</h3>
                {authService.isLoggedIn() ? (
                  <form onSubmit={submitReview} className="space-y-4">
                    <div className="text-center">
                      <Rate value={newReviewRating} onChange={setNewReviewRating} className="text-yellow-400 text-xl" />
                    </div>
                    <textarea
                      value={newReviewComment}
                      onChange={(e) => setNewReviewComment(e.target.value)}
                      placeholder="Sản phẩm tuyệt vời..."
                      className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:border-pink-400 focus:ring-1 focus:ring-pink-400 min-h-[100px] text-sm"
                      required
                    ></textarea>
                    <button
                      type="submit"
                      disabled={submittingReview}
                      className="w-full bg-emerald-400 hover:bg-emerald-500 text-white py-3 rounded-xl font-semibold transition flex items-center justify-center gap-2"
                    >
                      {submittingReview && <Loader2 size={18} className="animate-spin" />}
                      Gửi đánh giá
                    </button>
                  </form>
                ) : (
                  <div className="bg-gray-50 rounded-xl p-4 text-center text-sm text-gray-600">
                    Bạn cần <a href="/login" className="text-pink-500 font-semibold hover:underline">đăng nhập</a> để đánh giá.
                  </div>
                )}
              </div>
            </div>

            {/* Right List */}
            <div className="md:col-span-2">
              <h3 className="text-lg font-semibold text-gray-800 mb-6 border-b pb-4">Đánh giá mới nhất</h3>
              {reviews.length === 0 ? (
                <div className="text-center py-10 bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                  <p className="text-gray-500 italic">Chưa có đánh giá nào cho sản phẩm này.</p>
                </div>
              ) : (
                <div className="space-y-6">
                  {reviews.map((review, index) => (
                    <div key={review._id || index} className="border-b border-gray-50 pb-6 last:border-0 last:pb-0">
                      <div className="flex justify-between items-start mb-2">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 rounded-full bg-pink-100 flex items-center justify-center text-pink-600 font-bold uppercase">
                            {(review.user?.name || review.name || "U")[0]}
                          </div>
                          <div>
                            <p className="font-semibold text-gray-800">{review.user?.name || review.name || "Khách hàng"}</p>
                            <Rate disabled defaultValue={review.rating} className="text-yellow-400 text-xs mt-1" />
                          </div>
                        </div>
                        <p className="text-xs text-gray-400">
                          {review.createdAt ? new Date(review.createdAt).toLocaleDateString('vi-VN') : review.date}
                        </p>
                      </div>
                      <p className="text-gray-600 text-sm pl-13 mt-2 whitespace-pre-line leading-relaxed">
                        {review.comment || review.content}
                      </p>
                    </div>
                  ))}

                  {/* Pagination if needed */}
                  {totalReviews > reviews.length && (
                    <div className="text-center mt-6">
                      <button
                        onClick={() => setReviewParams(p => ({ ...p, limit: p.limit + 5 }))}
                        className="text-pink-500 font-medium text-sm hover:underline"
                      >
                        Xem thêm đánh giá
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* RELATED PRODUCTS */}
      {filteredRelated.length > 0 && (
        <div className="max-w-7xl mx-auto mt-20">
          <h2 className="text-emerald-400 text-2xl font-bold mb-10 text-center">
            Có thể bạn cũng thích 🌸
          </h2>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {filteredRelated.map((item) => (
              <ProductCard key={item._id} product={item} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductDetail;

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { message, Skeleton } from "antd";

import ProfileSidebar from "./ProfileSidebar";
import ProfileInfo from "./ProfileInfo";
import OrderHistory from "./OrderHistory";

import userService from "../../../services/userService";
import orderService from "../../../services/orderService";
import authService from "../../../services/authService";
import cartService from "../../../services/cartService";

const Profile = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploadingAvatar, setUploadingAvatar] = useState(false);

  const [user, setUser] = useState({
    name: "",
    email: "",
    phone: "",
    address: "",
    gender: "Khác",
    dateOfBirth: "",
    avatar: "",
  });

  const [addressParts, setAddressParts] = useState({
    city: "",
    district: "",
    ward: "",
    street: ""
  });

  const [orders, setOrders] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [passwordData, setPasswordData] = useState({
    currentPassword: "",
    newPassword: ""
  });
  const [showPasswordChange, setShowPasswordChange] = useState(false);



  useEffect(() => {
    // Check nếu chưa login thì đá về /login
    if (!authService.isLoggedIn()) {
      message.warning("Vui lòng đăng nhập để xem trang cá nhân");
      navigate("/login");
      return;
    }
    fetchData();
  }, [navigate]);

  const fetchData = async () => {
    try {
      setLoading(true);
      // Fetch Profile + Orders song song
      const [profileRes, ordersRes] = await Promise.all([
        userService.getProfile(),
        orderService.getMyOrders()
      ]);

      if (profileRes.success) {
        setUser({
          name: profileRes.data.name || "",
          email: profileRes.data.email || "",
          phone: profileRes.data.phone || "",
          address: profileRes.data.address || "",
          gender: profileRes.data.gender || "Khác",
          dateOfBirth: profileRes.data.dateOfBirth ? profileRes.data.dateOfBirth.substring(0, 10) : "",
          avatar: profileRes.data.avatar || "https://placehold.co/150",
        });

        // Split existing address if possible
        if (profileRes.data.address) {
          const parts = profileRes.data.address.split(" - ");
          if (parts.length === 4) {
             setAddressParts({
               street: parts[0] || "",
               ward: parts[1] || "",
               district: parts[2] || "",
               city: parts[3] || ""
             });
          } else {
             setAddressParts(prev => ({ ...prev, street: profileRes.data.address }));
          }
        }

        const currentUser = authService.getCurrentUser();
        const updatedUser = { ...profileRes.data, token: currentUser?.token };
        authService.saveUser(updatedUser);
      }

      if (ordersRes.success) {
        setOrders(ordersRes.data || []);
      }
    } catch (error) {
      console.error("Lỗi lấy thông tin:", error);
      message.error("Lỗi khi tải thông tin cá nhân");
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    setUser({ ...user, [e.target.name]: e.target.value });
  };

  const handleAddressChange = (e) => {
    setAddressParts({ ...addressParts, [e.target.name]: e.target.value });
  };

  const handlePasswordChange = (e) => {
    setPasswordData({ ...passwordData, [e.target.name]: e.target.value });
  };

  const handleAvatarChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      message.error('Vui lòng chọn file hình ảnh');
      return;
    }

    try {
      setUploadingAvatar(true);
      const formData = new FormData();
      formData.append('image', file);
      
      const res = await userService.uploadImage(formData);
      if (res.success) {
        // Chỉ cập nhật hiển thị cục bộ, chưa lưu vào back-end đến khi user nhấn "Lưu"
        // Hoặc có thể gọi API update profile ngay lập tức. Ta gọi ngay lập tức cho tiện dụng.
        const updateRes = await userService.updateProfile({
           name: user.name,
           email: user.email,
           phone: user.phone,
           address: user.address,
           avatar: res.imageUrl
        });
        
        if (updateRes.success) {
          setUser({ ...user, avatar: res.imageUrl });
          // Cập nhật local storage luôn để thay đổi hiện ra trên Header
          const currentUser = authService.getCurrentUser();
          const updatedUser = { ...updateRes.data, token: currentUser?.token };
          authService.saveUser(updatedUser);
          window.dispatchEvent(new Event("cartUpdated")); // Dùng đại event này hoặc tự dispatch profileUpdated
          message.success('Cập nhật ảnh đại diện thành công');
        }
      }
    } catch (error) {
      console.error(error);
      message.error(error?.response?.data?.message || 'Lỗi khi tải ảnh lên');
    } finally {
      setUploadingAvatar(false);
    }
  };

  const handleSaveProfile = async () => {
    if (!user.name || !user.email) {
      message.warning("Tên và Email không được để trống");
      return;
    }

    // Validate Email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(user.email)) {
      message.warning("Email không đúng định dạng");
      return;
    }

    // Validate Phone
    const phoneRegex = /^(0[3|5|7|8|9])+([0-9]{8})$/;
    if (user.phone && !phoneRegex.test(user.phone)) {
      message.warning("Số điện thoại không hợp lệ (phải gồm 10 số hợp lệ tại VN)");
      return;
    }

    setSaving(true);
    try {
      // Assemble the full address
      let fullAddress = user.address;
      if (addressParts.city || addressParts.district || addressParts.ward || addressParts.street) {
        fullAddress = [addressParts.street, addressParts.ward, addressParts.district, addressParts.city]
          .filter(Boolean)
          .join(" - ");
      }

      const payload = {
        name: user.name,
        email: user.email,
        phone: user.phone,
        address: fullAddress,
        gender: user.gender,
        dateOfBirth: user.dateOfBirth
      };

      // Xử lý đổi password nếu có nhập
      if (showPasswordChange) {
        if (!passwordData.currentPassword || !passwordData.newPassword) {
          message.warning("Vui lòng nhập đủ mật khẩu cũ và mới");
          setSaving(false);
          return;
        }
        if (passwordData.newPassword.length < 6) {
          message.warning("Mật khẩu mới phải từ 6 ký tự");
          setSaving(false);
          return;
        }
        payload.currentPassword = passwordData.currentPassword;
        payload.newPassword = passwordData.newPassword;
      }

      const res = await userService.updateProfile(payload);
      if (res.success) {
        message.success("Cập nhật thông tin thành công!");
        setIsEditing(false);
        setShowPasswordChange(false);
        setPasswordData({ currentPassword: "", newPassword: "" });

        // Giữ lại token cũ khi update profile
        const currentUser = authService.getCurrentUser();
        const updatedUser = { ...res.data, token: currentUser?.token };
        authService.saveUser(updatedUser); // Update local storage
      }
    } catch (error) {
      message.error(error?.response?.data?.message || "Cập nhật thất bại");
    } finally {
      setSaving(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    window.dispatchEvent(new Event("cartUpdated")); // Reset cart badge
    message.success("Đã đăng xuất");
    navigate("/login");
  };

  const handleReorder = async (order) => {
    try {
      let successCount = 0;
      for (const item of order.orderItems) {
        if (item.product?._id) {
          const res = await cartService.addToCart(item.product._id, item.quantity);
          if (res.success) successCount++;
        }
      }
      if (successCount > 0) {
        window.dispatchEvent(new Event("cartUpdated"));
        message.success(`Đã thêm ${successCount} sản phẩm vào giỏ hàng`);
        navigate('/cart');
      } else {
        message.warning("Không thể thêm sản phẩm nào vào giỏ");
      }
    } catch (error) {
      message.error("Có lỗi khi thêm vào giỏ hàng");
    }
  };

  return (
    <div className="bg-[#fffafc] min-h-screen py-14 px-6">
      <div className="max-w-6xl mx-auto grid md:grid-cols-3 gap-10">
        
        {loading ? (
          <>
            {/* Sidebar Skeleton */}
            <div className="bg-white rounded-3xl shadow-lg p-8 h-fit">
              <Skeleton.Avatar active size={130} shape="circle" className="mx-auto block mb-6" />
              <Skeleton active paragraph={{ rows: 2, width: ['100%', '80%'] }} title={{ width: '60%' }} className="text-center flex flex-col items-center" />
              <Skeleton.Button active block shape="round" className="mt-8 h-10" />
            </div>
            
            {/* Content Skeleton */}
            <div className="md:col-span-2 space-y-10">
              <div className="bg-white rounded-3xl shadow-lg p-10">
                <Skeleton active title={{ width: 200 }} paragraph={{ rows: 6 }} />
              </div>
              <div className="bg-white rounded-3xl shadow-lg p-10">
                <Skeleton active title={{ width: 250 }} paragraph={{ rows: 8 }} />
              </div>
            </div>
          </>
        ) : (
          <>
            <ProfileSidebar 
              user={user} 
              uploadingAvatar={uploadingAvatar} 
              handleAvatarChange={handleAvatarChange} 
              handleLogout={handleLogout} 
              orderCount={orders.length}
            />

            <div className="md:col-span-2 space-y-10">
              <ProfileInfo 
                user={user}
                isEditing={isEditing}
                setIsEditing={setIsEditing}
                handleChange={handleChange}
                addressParts={addressParts}
                handleAddressChange={handleAddressChange}
                showPasswordChange={showPasswordChange}
                setShowPasswordChange={setShowPasswordChange}
                passwordData={passwordData}
                handlePasswordChange={handlePasswordChange}
                handleSaveProfile={handleSaveProfile}
                saving={saving}
              />
              
              <OrderHistory 
                orders={orders} 
                handleReorder={handleReorder}
              />
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default Profile;

import { useEffect, useState } from "react";
import { Trash2, ShoppingCart, Loader2 } from "lucide-react";
import { Link } from "react-router-dom";
import wishlistService from "../../../services/wishlistService";
import cartService from "../../../services/cartService";
import authService from "../../../services/authService";
import { message } from "antd";

const Wishlist = () => {
  const [wishlist, setWishlist] = useState([]);
  const [loading, setLoading] = useState(true);
  const [addingToCart, setAddingToCart] = useState(null);

  const loadWishlist = async () => {
    if (!authService.isLoggedIn()) {
      setLoading(false);
      return;
    }
    setLoading(true);
    try {
      const res = await wishlistService.getWishlist();
      if (res.success) {
        setWishlist(res.data?.products || []);
      }
    } catch (error) {
      console.error("Lỗi khi lấy wishlist:", error);
      message.error("Không thể tải danh sách yêu thích");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadWishlist();
    window.addEventListener("wishlistUpdated", loadWishlist);
    return () => {
      window.removeEventListener("wishlistUpdated", loadWishlist);
    };
  }, []);

  const removeItem = async (id) => {
    try {
      const res = await wishlistService.removeFromWishlist(id);
      if (res.success) {
        setWishlist(wishlist.filter((item) => item._id !== id));
        window.dispatchEvent(new Event("wishlistUpdated"));
        message.success("Đã xoá khỏi danh sách yêu thích");
      }
    } catch (error) {
      message.error("Lỗi khi xoá sản phẩm khỏi wishlist");
    }
  };

  const clearWishlist = async () => {
    // Không có API clear all, remove the button implementation or loop
    message.warning("Tính năng này đang được cập nhật");
  };

  const handleAddToCart = async (product) => {
    if (!authService.isLoggedIn()) {
      message.warning("Vui lòng đăng nhập để mua hàng");
      return;
    }

    setAddingToCart(product._id);
    try {
      const res = await cartService.addToCart(product._id, 1);
      if (res.success) {
        message.success(`Đã thêm ${product.name} vào giỏ`);
        window.dispatchEvent(new Event("cartUpdated"));
      }
    } catch (error) {
      message.error(error?.response?.data?.message || "Lỗi khi thêm vào giỏ hàng");
    } finally {
      setAddingToCart(null);
    }
  };

  if (loading) {
    return (
      <div className="bg-[#fffafc] min-h-screen flex items-center justify-center p-10 text-pink-400">
        <Loader2 className="animate-spin w-12 h-12 mb-4" />
        <p>Đang tải danh sách yêu thích...</p>
      </div>
    );
  }

  return (
    <div className="bg-[#fffafc] min-h-screen shop-wrapper">

      {/* Hoa rơi */}
      <img src="https://res.cloudinary.com/drwles2k0/image/upload/v1772271283/flower_lmks7o.png" className="floweruy f1" alt="" />
      <img src="https://res.cloudinary.com/drwles2k0/image/upload/v1772271283/flower_lmks7o.png" className="floweruy f2" alt="" />
      <img src="https://res.cloudinary.com/drwles2k0/image/upload/v1772271283/flower_lmks7o.png" className="floweruy f3" alt="" />
      <img src="https://res.cloudinary.com/drwles2k0/image/upload/v1772271283/flower_lmks7o.png" className="floweruy f4" alt="" />
      <img src="https://res.cloudinary.com/drwles2k0/image/upload/v1772271283/flower_lmks7o.png" className="floweruy f5" alt="" />

      <div className="relative z-10" />

      {/* Banner */}
      <div className="text-center mb-8 relative">
        <h1 className="text-[#88a82a] font-medium tracking-widest uppercase px-6 pt-6">
          Sản Phẩm Yêu Thích 💗
        </h1>
        <p className="shop-sub">
          Khám phá thêm hoa 🌷
        </p>
      </div>

      <div className="max-w-5xl mx-auto px-6 py-6">

        {wishlist.length === 0 ? (
          <div className="text-center">
            <p className="text-gray-500 mb-6">
              Bạn chưa có sản phẩm yêu thích 😢
            </p>

            <Link
              to="/shop"
              className="bg-pink-500 text-white px-6 py-2 rounded-full hover:bg-pink-600 transition"
            >
              Khám phá sản phẩm
            </Link>
          </div>
        ) : (
          <>
            {/* Nút xoá tất cả */}
            <div className="flex justify-end mb-6">
              <button
                onClick={clearWishlist}
                className="px-6 py-2 bg-rose-300 text-white rounded-full hover:bg-rose-400 transition duration-300 text-sm font-semibold shadow-sm"
              >
                Xoá tất cả
              </button>
            </div>

            {/* LIST sản phẩm */}
            <div className="space-y-6">
              {wishlist.map((product) => (
                <div
                  key={product._id}
                  className="flex items-center justify-between bg-white p-5 rounded-2xl shadow-md hover:shadow-lg hover:scale-[1.01] transition"
                >

                  {/* Bên trái */}
                  <div className="flex items-center gap-6">
                    <Link to={`/product/${product._id}`} state={{ product }}>
                      <img
                        src={product.images?.[0]?.url || product.images?.[0]}
                        alt={product.name}
                        className="w-28 h-28 object-cover rounded-xl hover:scale-105 transition"
                      />
                    </Link>

                    <div>
                      <Link to={`/product/${product._id}`} state={{ product }}>
                        <h3 className="text-lg font-semibold text-gray-800 hover:text-pink-500 transition">
                          {product.name}
                        </h3>
                      </Link>

                      <p className="text-pink-500 font-bold mt-2">
                        {product.price.toLocaleString()} đ
                      </p>
                    </div>
                  </div>
                  {/* Bên phải */}
                  <div className="flex items-center gap-4">

                    <button
                      onClick={() => handleAddToCart(product)}
                      disabled={addingToCart === product._id}
                      className="flex items-center justify-center gap-2 px-4 py-2 bg-emerald-200 text-emerald-700 rounded-full hover:bg-emerald-300 transition duration-300 text-sm font-medium"                    >
                      {addingToCart === product._id ? <Loader2 size={18} className="animate-spin" /> : <ShoppingCart size={18} />}
                      Thêm vào giỏ
                    </button>

                    <button
                      onClick={() => removeItem(product._id)}
                      className="px-4 py-2 bg-pink-200 text-pink-700 rounded-full hover:bg-pink-300 transition duration-300 text-sm font-medium"
                    >
                      <Trash2 size={18} />
                    </button>

                  </div>
                </div>
              ))}
            </div>
          </>
        )}

      </div>
    </div>
  );
};

export default Wishlist;
